('60000000-0000-0000-0000-000000000013','Isaac Newton','isaac.newton@example.com','07000010013',NULL,'Formulated the laws of motion and universal gravitation, laying the groundwork for classical physics.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','inactive',NULL,NULL,v_ts,v_ts),
