('60000000-0000-0000-0000-000000000015','Leonardo da Vinci','leonardo.davinci@example.com','07000010015',NULL,'A true polymath whose genius spanned art, science, engineering, and anatomy.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','active',NULL,NULL,v_ts,v_ts),
('60000000-0000-0000-0000-000000000016','Michelangelo','michelangelo@example.com','07000010016',NULL,'Master sculptor of David and painter of the Sistine Chapel ceiling, he defined Renaissance artistry.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','inactive',NULL,NULL,v_ts,v_ts),
('60000000-0000-0000-0000-000000000017','Johann Wolfgang von Goethe','goethe@example.com','07000010017',NULL,'German writer and statesman, his “Faust” remains a cornerstone of world literature.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','inactive',NULL,NULL,v_ts,v_ts),
('60000000-0000-0000-0000-000000000018','Emily Brontë','emily.bronte@example.com','07000010018',NULL,'Author of Wuthering Heights, her work explored passion, isolation, and the natural world.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','inactive',NULL,NULL,v_ts,v_ts),
('60000000-0000-0000-0000-000000000019','Edgar Allan Poe','edgar.poe@example.com','07000010019',NULL,'Father of the short story and detective fiction, he delved into the macabre and the mind.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','inactive',NULL,NULL,v_ts,v_ts),
('60000000-0000-0000-0000-000000000020','Frida Kahlo','frida.kahlo@example.com','07000010020',NULL,'Mexican painter known for her vivid self‑portraits that confronted gender, class, and identity.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','inactive',NULL,NULL,v_ts,v_ts),
('60000000-0000-0000-0000-000000000021','Nelson Mandela','nelson.mandela@example.com','07000010021',NULL,'Anti‑apartheid revolutionary and South Africa’s first black president, he championed reconciliation.','41000000-0000-0000-0000-000000000002','41000000-0000-0000-0000-000000000002','active',NULL,NULL,v_ts,v_ts),
